import fs from "node:fs";
import path from "node:path";

const files = {"README.md": "# PfotenTechnik Advisor 2.0\n\nPremium-Kaufberater für Futterautomaten mit:\n\n- mobile-first UX\n- sechs geführten Schritten\n- Live-Zwischenauswertung\n- qualitativen Passungsstufen\n- harten Ausschlussregeln\n- drei nachvollziehbaren Empfehlungen\n- Vergleich nur der Unterschiede\n- URL-Sharing\n- lokalem Wiederherstellen der Auswahl\n- passenden Ratgebern\n- barrierearmer Tastaturbedienung\n- reduzierten Animationen bei `prefers-reduced-motion`\n\n## Installation\n\nIm Repository-Root:\n\n```bash\nnode install-advisor-2.mjs\nnpm run build:pfotentechnik\n```\n\nDanach:\n\n```text\n/futterautomat-berater/\n```\n\nDer Installer überschreibt keine vorhandenen Dateien.\n\n## Empfohlener Rollout\n\n1. Route installieren und Build prüfen.\n2. Intern testen.\n3. Link im Cornerstone ergänzen.\n4. Link auf der Startseite ergänzen.\n5. Erst danach Tracking aktivieren.\n", "docs/PFOTENTECHNIK_ADVISOR_2.md": "# PfotenTechnik Advisor 2.0\n\n## UX-Ziel\n\nDer Advisor soll sich wie eine ruhige, kompetente Kaufberatung anfühlen,\nnicht wie ein Filterformular.\n\n## Nutzerstrecke\n\n1. Tierart\n2. Anzahl Tiere\n3. Futterart\n4. gewünschte Funktionen\n5. Preisklasse\n6. Entscheidungsstil\n7. Ergebnis\n8. Unterschiede vergleichen\n9. passende Ratgeber\n\n## Passungsstufen\n\n- Sehr gute Passung\n- Gute Passung\n- Mit Einschränkungen\n- Nicht passend\n\nDie interne Punktzahl wird nicht prominent angezeigt.\n\n## Harte Ausschlüsse\n\n- Nassfutter gewählt, Produkt nur für Trockenfutter\n- Trockenfutter gewählt, Produkt nur für Nassfutter\n- Mikrochip als Priorität, Produkt ohne Zugangskontrolle\n- Mehrtierhaushalt plus Futterneid-Indikator ohne Zugangskontrolle\n\n## Zustandsmodell\n\nDie Antworten werden:\n\n- in der URL als Query-Parameter gespeichert\n- lokal im Browser gespeichert\n- nicht an einen Server gesendet\n\n## Datenschutz\n\nKeine E-Mail-Abfrage.\nKeine personenbezogene Speicherung.\nKeine serverseitige Profilbildung.\n\n## Accessibility\n\n- echte `fieldset`- und `legend`-Struktur\n- große Touch-Ziele\n- sichtbarer Fokus\n- Screenreader-Livebereiche\n- keine Information nur über Farbe\n- reduzierte Bewegung respektiert\n", "apps/pfotentechnik/src/domain/advisor/types.ts": "export type AdvisorPet = \"cat\" | \"dog\";\nexport type AdvisorPetCount = \"one\" | \"multiple\";\nexport type AdvisorFood = \"dry\" | \"wet\" | \"mixed\";\nexport type AdvisorBudget = \"budget\" | \"midrange\" | \"premium\" | \"open\";\nexport type AdvisorPriority =\n  | \"camera\"\n  | \"app\"\n  | \"offline\"\n  | \"backup\"\n  | \"microchip\"\n  | \"simple\";\nexport type AdvisorDecisionStyle = \"best-match\" | \"safe-choice\";\n\nexport type AdvisorAnswers = {\n  pet: AdvisorPet;\n  petCount: AdvisorPetCount;\n  food: AdvisorFood;\n  priorities: AdvisorPriority[];\n  budget: AdvisorBudget;\n  decisionStyle: AdvisorDecisionStyle;\n};\n\nexport type AdvisorProduct = {\n  id: string;\n  slug: string;\n  title: string;\n  description: string;\n  recommendation: string;\n  rating: number;\n  score?: number;\n  bestFor: string[];\n  attention: string[];\n  strengths: string[];\n  weaknesses: string[];\n  features: string[];\n  useCase?: string;\n  priceCategory?: \"budget\" | \"midrange\" | \"premium\";\n  foodType: Array<\"dry\" | \"wet\">;\n  app?: boolean;\n  camera?: boolean;\n  access?: \"open\" | \"microchip\";\n  backupPower?: boolean;\n  route: string;\n};\n\nexport type AdvisorFit = \"excellent\" | \"good\" | \"limited\" | \"none\";\n\nexport type AdvisorMatch = {\n  product: AdvisorProduct;\n  score: number;\n  fit: AdvisorFit;\n  reasons: string[];\n  cautions: string[];\n  exclusions: string[];\n  matchedPriorities: AdvisorPriority[];\n};\n\nexport type AdvisorGuide = {\n  title: string;\n  href: string;\n  description: string;\n  when: (answers: AdvisorAnswers) => boolean;\n};\n", "apps/pfotentechnik/src/domain/advisor/mapProduct.ts": "import type { CollectionEntry } from \"astro:content\";\nimport type { AdvisorProduct } from \"./types\";\n\nexport const mapProductToAdvisor = (\n  entry: CollectionEntry<\"products\">\n): AdvisorProduct => {\n  const data = entry.data;\n  const slug = entry.id.replace(/\\.(md|mdx)$/i, \"\");\n\n  return {\n    id: entry.id,\n    slug,\n    title: data.title,\n    description: data.description,\n    recommendation: data.recommendation,\n    rating: data.rating,\n    score: data.score,\n    bestFor: data.decision.bestFor,\n    attention: data.decision.attention,\n    strengths: data.strengths,\n    weaknesses: data.weaknesses,\n    features: data.features,\n    useCase: data.useCase,\n    priceCategory:\n      data.priceCategory ??\n      data.comparisonFilters?.priceTier,\n    foodType: data.comparisonFilters?.foodType ?? [],\n    app: data.comparisonFilters?.app,\n    camera: data.comparisonFilters?.camera,\n    access: data.comparisonFilters?.access,\n    backupPower: data.comparisonFilters?.backupPower,\n    route: `/produkt/${slug}/`\n  };\n};\n", "apps/pfotentechnik/src/domain/advisor/recommendProducts.ts": "import type {\n  AdvisorAnswers,\n  AdvisorMatch,\n  AdvisorPriority,\n  AdvisorProduct\n} from \"./types\";\n\nconst searchableText = (product: AdvisorProduct) =>\n  [\n    product.title,\n    product.description,\n    product.recommendation,\n    product.useCase,\n    ...product.bestFor,\n    ...product.attention,\n    ...product.strengths,\n    ...product.weaknesses,\n    ...product.features\n  ]\n    .filter(Boolean)\n    .join(\" \")\n    .toLocaleLowerCase(\"de-DE\");\n\nconst hasAny = (product: AdvisorProduct, terms: string[]) => {\n  const haystack = searchableText(product);\n  return terms.some((term) =>\n    haystack.includes(term.toLocaleLowerCase(\"de-DE\"))\n  );\n};\n\nconst priorityLabels: Record<AdvisorPriority, string> = {\n  camera: \"Kamera\",\n  app: \"App-Steuerung\",\n  offline: \"Offline-Betrieb\",\n  backup: \"Notstrom\",\n  microchip: \"Mikrochip-Zugang\",\n  simple: \"einfache Bedienung\"\n};\n\nconst priorityMatch = (\n  product: AdvisorProduct,\n  priority: AdvisorPriority\n) => {\n  switch (priority) {\n    case \"camera\":\n      return product.camera === true || hasAny(product, [\"kamera\"]);\n    case \"app\":\n      return product.app === true || hasAny(product, [\"app\"]);\n    case \"offline\":\n      return hasAny(product, [\n        \"offline\",\n        \"ohne wlan\",\n        \"ohne internet\",\n        \"lokaler zeitplan\",\n        \"zeitplan ohne internet\"\n      ]);\n    case \"backup\":\n      return (\n        product.backupPower === true ||\n        hasAny(product, [\"notstrom\", \"batterie\", \"backup\"])\n      );\n    case \"microchip\":\n      return (\n        product.access === \"microchip\" ||\n        hasAny(product, [\"mikrochip\"])\n      );\n    case \"simple\":\n      return (\n        product.app !== true &&\n        product.camera !== true &&\n        hasAny(product, [\n          \"einfach\",\n          \"ohne app\",\n          \"manuell\",\n          \"übersichtlich\"\n        ])\n      );\n  }\n};\n\nconst animalMatch = (\n  product: AdvisorProduct,\n  pet: AdvisorAnswers[\"pet\"]\n) =>\n  pet === \"cat\"\n    ? hasAny(product, [\"katze\", \"katzen\", \"mehrkatzen\"])\n    : hasAny(product, [\"hund\", \"hunde\"]);\n\nexport const recommendAdvisorProducts = (\n  products: AdvisorProduct[],\n  answers: AdvisorAnswers\n): AdvisorMatch[] => {\n  return products\n    .map((product) => {\n      let score = 28;\n      const reasons: string[] = [];\n      const cautions: string[] = [];\n      const exclusions: string[] = [];\n      const matchedPriorities: AdvisorPriority[] = [];\n\n      const supportsDry = product.foodType.includes(\"dry\");\n      const supportsWet = product.foodType.includes(\"wet\");\n\n      if (answers.food === \"dry\") {\n        if (supportsDry) {\n          score += 25;\n          reasons.push(\"für Trockenfutter geeignet\");\n        } else {\n          exclusions.push(\"nicht für Trockenfutter ausgewiesen\");\n        }\n      }\n\n      if (answers.food === \"wet\") {\n        if (supportsWet) {\n          score += 25;\n          reasons.push(\"für Nassfutter geeignet\");\n        } else {\n          exclusions.push(\"nicht für Nassfutter ausgewiesen\");\n        }\n      }\n\n      if (answers.food === \"mixed\") {\n        if (supportsDry && supportsWet) {\n          score += 25;\n          reasons.push(\"für Nass- und Trockenfutter geeignet\");\n        } else if (supportsDry || supportsWet) {\n          score -= 8;\n          cautions.push(\n            \"deckt nur eine der gewünschten Futterarten ab\"\n          );\n        } else {\n          exclusions.push(\n            \"keine passende Futterart dokumentiert\"\n          );\n        }\n      }\n\n      if (animalMatch(product, answers.pet)) {\n        score += 10;\n        reasons.push(\n          answers.pet === \"cat\"\n            ? \"für Katzen eingeordnet\"\n            : \"für Hunde eingeordnet\"\n        );\n      }\n\n      if (answers.petCount === \"multiple\") {\n        const multiPetSuitable =\n          product.access === \"microchip\" ||\n          hasAny(product, [\n            \"mehrtier\",\n            \"mehrkatzen\",\n            \"mehrere tiere\",\n            \"futterneid\",\n            \"mikrochip\"\n          ]);\n\n        if (multiPetSuitable) {\n          score += 18;\n          reasons.push(\n            \"für mehrere Tiere besonders relevant\"\n          );\n        } else {\n          score -= 8;\n          cautions.push(\n            \"keine eindeutige Zugangskontrolle für mehrere Tiere\"\n          );\n        }\n      }\n\n      for (const priority of answers.priorities) {\n        if (priorityMatch(product, priority)) {\n          matchedPriorities.push(priority);\n          score += priority === \"microchip\" ? 17 : 11;\n          reasons.push(`${priorityLabels[priority]} vorhanden`);\n        } else if (priority === \"microchip\") {\n          exclusions.push(\n            \"keine Mikrochip-Zugangskontrolle\"\n          );\n        } else {\n          score -= 5;\n          cautions.push(\n            `${priorityLabels[priority]} nicht eindeutig dokumentiert`\n          );\n        }\n      }\n\n      if (\n        answers.budget !== \"open\" &&\n        product.priceCategory === answers.budget\n      ) {\n        score += 10;\n        reasons.push(\"passt zur gewählten Preisklasse\");\n      } else if (\n        answers.budget !== \"open\" &&\n        product.priceCategory\n      ) {\n        score -= 3;\n        cautions.push(\n          \"liegt außerhalb der bevorzugten Preisklasse\"\n        );\n      }\n\n      score += Math.round(product.rating * 2);\n      score += Math.round(\n        (product.score ?? product.rating * 20) / 25\n      );\n\n      score = Math.max(0, Math.min(100, score));\n\n      const fit =\n        exclusions.length > 0\n          ? \"none\"\n          : score >= 78\n            ? \"excellent\"\n            : score >= 60\n              ? \"good\"\n              : score >= 38\n                ? \"limited\"\n                : \"none\";\n\n      return {\n        product,\n        score,\n        fit,\n        reasons: [...new Set(reasons)].slice(0, 5),\n        cautions: [...new Set(cautions)].slice(0, 4),\n        exclusions: [...new Set(exclusions)],\n        matchedPriorities\n      };\n    })\n    .sort((left, right) => {\n      if (\n        left.exclusions.length !== right.exclusions.length\n      ) {\n        return (\n          left.exclusions.length -\n          right.exclusions.length\n        );\n      }\n\n      if (\n        answers.decisionStyle === \"safe-choice\" &&\n        left.cautions.length !== right.cautions.length\n      ) {\n        return left.cautions.length - right.cautions.length;\n      }\n\n      return right.score - left.score;\n    });\n};\n", "apps/pfotentechnik/src/domain/advisor/guides.ts": "import type { AdvisorGuide } from \"./types\";\n\nexport const advisorGuides: AdvisorGuide[] = [\n  {\n    title: \"Smarte Futterautomaten richtig auswählen\",\n    href: \"/smarte-futterautomaten/\",\n    description:\n      \"Bauarten, Funktionen, Offline-Betrieb und Kaufkriterien im Überblick.\",\n    when: () => true\n  },\n  {\n    title: \"Futterautomaten für mehrere Katzen\",\n    href: \"/futterautomat-fuer-zwei-katzen/\",\n    description:\n      \"Zugangskontrolle, Futterneid und getrennte Fütterung verständlich erklärt.\",\n    when: (answers) => answers.petCount === \"multiple\"\n  },\n  {\n    title: \"Futterautomaten für Nassfutter\",\n    href: \"/futterautomat-nassfutter/\",\n    description:\n      \"Kühlung, Fächerlösungen und Hygiene bei Nassfutter.\",\n    when: (answers) =>\n      answers.food === \"wet\" || answers.food === \"mixed\"\n  },\n  {\n    title: \"Futterautomaten ohne WLAN\",\n    href: \"/futterautomat-ohne-wlan/\",\n    description:\n      \"Welche Modelle auch ohne dauerhafte Cloud-Verbindung sinnvoll sind.\",\n    when: (answers) =>\n      answers.priorities.includes(\"offline\")\n  },\n  {\n    title: \"Futterautomaten mit Kamera\",\n    href: \"/futterautomat-mit-kamera/\",\n    description:\n      \"Kameraqualität, App-Funktionen und Datenschutz einordnen.\",\n    when: (answers) =>\n      answers.priorities.includes(\"camera\")\n  },\n  {\n    title: \"Futterautomat richtig reinigen\",\n    href: \"/futterautomat-richtig-reinigen/\",\n    description:\n      \"Hygiene, Förderschacht, Rotor und häufig vergessene Stellen.\",\n    when: () => true\n  }\n];\n", "apps/pfotentechnik/src/domain/advisor/urlState.ts": "import type { AdvisorAnswers } from \"./types\";\n\nconst separator = \",\";\n\nexport const serializeAdvisorAnswers = (\n  answers: AdvisorAnswers\n) => {\n  const params = new URLSearchParams();\n  params.set(\"pet\", answers.pet);\n  params.set(\"count\", answers.petCount);\n  params.set(\"food\", answers.food);\n  params.set(\"budget\", answers.budget);\n  params.set(\"style\", answers.decisionStyle);\n\n  if (answers.priorities.length > 0) {\n    params.set(\n      \"features\",\n      answers.priorities.join(separator)\n    );\n  }\n\n  return params;\n};\n\nexport const parseAdvisorAnswers = (\n  params: URLSearchParams\n): AdvisorAnswers | null => {\n  const pet = params.get(\"pet\");\n  const petCount = params.get(\"count\");\n  const food = params.get(\"food\");\n  const budget = params.get(\"budget\");\n  const decisionStyle = params.get(\"style\");\n  const priorities = (params.get(\"features\") ?? \"\")\n    .split(separator)\n    .filter(Boolean);\n\n  if (\n    ![\"cat\", \"dog\"].includes(pet ?? \"\") ||\n    ![\"one\", \"multiple\"].includes(petCount ?? \"\") ||\n    ![\"dry\", \"wet\", \"mixed\"].includes(food ?? \"\") ||\n    ![\"budget\", \"midrange\", \"premium\", \"open\"].includes(\n      budget ?? \"\"\n    ) ||\n    ![\"best-match\", \"safe-choice\"].includes(\n      decisionStyle ?? \"\"\n    )\n  ) {\n    return null;\n  }\n\n  return {\n    pet: pet as AdvisorAnswers[\"pet\"],\n    petCount: petCount as AdvisorAnswers[\"petCount\"],\n    food: food as AdvisorAnswers[\"food\"],\n    budget: budget as AdvisorAnswers[\"budget\"],\n    decisionStyle:\n      decisionStyle as AdvisorAnswers[\"decisionStyle\"],\n    priorities: priorities.filter((priority) =>\n      [\n        \"camera\",\n        \"app\",\n        \"offline\",\n        \"backup\",\n        \"microchip\",\n        \"simple\"\n      ].includes(priority)\n    ) as AdvisorAnswers[\"priorities\"]\n  };\n};\n", "apps/pfotentechnik/src/domain/advisor/index.ts": "export * from \"./types\";\nexport * from \"./mapProduct\";\nexport * from \"./recommendProducts\";\nexport * from \"./guides\";\nexport * from \"./urlState\";\n", "apps/pfotentechnik/src/components/advisor/AdvisorCompare.astro": "---\nimport type { AdvisorMatch } from \"../../domain/advisor\";\n\nconst { matches } = Astro.props as {\n  matches: AdvisorMatch[];\n};\n\nconst rows = [\n  {\n    label: \"Futterart\",\n    value: (match: AdvisorMatch) =>\n      match.product.foodType\n        .map((type) =>\n          type === \"dry\" ? \"Trockenfutter\" : \"Nassfutter\"\n        )\n        .join(\" & \") || \"nicht dokumentiert\"\n  },\n  {\n    label: \"App\",\n    value: (match: AdvisorMatch) =>\n      match.product.app === true ? \"Ja\" : \"Nicht ausgewiesen\"\n  },\n  {\n    label: \"Kamera\",\n    value: (match: AdvisorMatch) =>\n      match.product.camera === true ? \"Ja\" : \"Nein\"\n  },\n  {\n    label: \"Zugang\",\n    value: (match: AdvisorMatch) =>\n      match.product.access === \"microchip\"\n        ? \"Mikrochip\"\n        : \"Offen\"\n  },\n  {\n    label: \"Notstrom\",\n    value: (match: AdvisorMatch) =>\n      match.product.backupPower === true\n        ? \"Ja\"\n        : \"Nicht ausgewiesen\"\n  },\n  {\n    label: \"Preisklasse\",\n    value: (match: AdvisorMatch) =>\n      ({\n        budget: \"Preisbewusst\",\n        midrange: \"Mittelklasse\",\n        premium: \"Premium\"\n      })[match.product.priceCategory ?? \"\"] ??\n      \"Nicht eingeordnet\"\n  }\n];\n\nconst differenceRows = rows.filter((row) => {\n  const values = matches.map(row.value);\n  return new Set(values).size > 1;\n});\n---\n\n{\n  matches.length > 1 && (\n    <section class=\"compare\" aria-labelledby=\"compare-heading\">\n      <div class=\"compare-heading\">\n        <p>Direktvergleich</p>\n        <h2 id=\"compare-heading\">Nur die Unterschiede</h2>\n      </div>\n\n      <div class=\"compare-scroll\">\n        <table>\n          <thead>\n            <tr>\n              <th scope=\"col\">Kriterium</th>\n              {matches.map((match) => (\n                <th scope=\"col\">{match.product.title}</th>\n              ))}\n            </tr>\n          </thead>\n          <tbody>\n            {differenceRows.map((row) => (\n              <tr>\n                <th scope=\"row\">{row.label}</th>\n                {matches.map((match) => (\n                  <td>{row.value(match)}</td>\n                ))}\n              </tr>\n            ))}\n          </tbody>\n        </table>\n      </div>\n    </section>\n  )\n}\n\n<style>\n  .compare {\n    margin-top: 44px;\n    padding-top: 36px;\n    border-top: 1px solid #e2e8f0;\n  }\n\n  .compare-heading p {\n    margin: 0 0 6px;\n    color: #2e7d32;\n    font-size: 0.8rem;\n    font-weight: 800;\n    letter-spacing: 0.08em;\n    text-transform: uppercase;\n  }\n\n  .compare-heading h2 {\n    margin: 0 0 22px;\n    font-size: clamp(1.55rem, 4vw, 2.5rem);\n  }\n\n  .compare-scroll {\n    overflow-x: auto;\n    border: 1px solid #e2e8f0;\n    border-radius: 18px;\n  }\n\n  table {\n    width: 100%;\n    min-width: 720px;\n    border-collapse: collapse;\n  }\n\n  th,\n  td {\n    padding: 16px;\n    border-bottom: 1px solid #e2e8f0;\n    text-align: left;\n    vertical-align: top;\n  }\n\n  thead th {\n    background: #f8fafc;\n  }\n\n  tbody th {\n    color: #334155;\n  }\n</style>\n", "apps/pfotentechnik/src/components/advisor/PetAdvisor.astro": "---\nimport type { AdvisorProduct } from \"../../domain/advisor\";\nimport { advisorGuides } from \"../../domain/advisor\";\n\nconst { products } = Astro.props as {\n  products: AdvisorProduct[];\n};\n\nconst guideData = advisorGuides.map(\n  ({ title, href, description }) => ({\n    title,\n    href,\n    description\n  })\n);\n---\n\n<section\n  class=\"advisor\"\n  data-advisor\n  data-products={JSON.stringify(products)}\n  data-guides={JSON.stringify(guideData)}\n>\n  <header class=\"advisor-hero\">\n    <p class=\"eyebrow\">PfotenTechnik Advisor 2.0</p>\n    <h1>Welcher Futterautomat passt wirklich zu deinem Alltag?</h1>\n    <p class=\"lead\">\n      Sechs kurze Fragen führen zu einer nachvollziehbaren\n      Auswahl. Du siehst nicht nur Empfehlungen, sondern auch\n      Einschränkungen und echte Unterschiede.\n    </p>\n\n    <div class=\"trust-row\" aria-label=\"Hinweise zum Advisor\">\n      <span>Keine E-Mail nötig</span>\n      <span>Keine Preisversprechen</span>\n      <span>Keine versteckte Vorauswahl</span>\n    </div>\n  </header>\n\n  <div class=\"advisor-panel\">\n    <div class=\"advisor-status\" data-status>\n      <div class=\"status-copy\">\n        <span data-progress-label>Frage 1 von 6</span>\n        <strong data-progress-title>Tierart</strong>\n      </div>\n      <div\n        class=\"progress-track\"\n        role=\"progressbar\"\n        aria-valuemin=\"1\"\n        aria-valuemax=\"6\"\n        aria-valuenow=\"1\"\n        data-progress\n      >\n        <span data-progress-bar></span>\n      </div>\n      <p class=\"live-note\" data-live-note aria-live=\"polite\">\n        Wir starten mit den grundlegenden Anforderungen.\n      </p>\n    </div>\n\n    <form data-form novalidate>\n      <fieldset data-step=\"0\">\n        <legend>Für welches Tier suchst du?</legend>\n        <p class=\"step-help\">\n          Tierart und Körpergröße beeinflussen Bauform,\n          Napfhöhe und Portionsbedarf.\n        </p>\n\n        <div class=\"choice-grid choice-grid--two\">\n          <label class=\"choice-card\">\n            <input\n              type=\"radio\"\n              name=\"pet\"\n              value=\"cat\"\n              required\n            />\n            <span>\n              <strong>Katze</strong>\n              <small>Eine oder mehrere Katzen</small>\n              <em>\n                Kleine Portionen und Zugang besonders beachten\n              </em>\n            </span>\n          </label>\n\n          <label class=\"choice-card\">\n            <input\n              type=\"radio\"\n              name=\"pet\"\n              value=\"dog\"\n              required\n            />\n            <span>\n              <strong>Hund</strong>\n              <small>Kleine bis große Hunde</small>\n              <em>\n                Kapazität und Napfhöhe stärker gewichten\n              </em>\n            </span>\n          </label>\n        </div>\n      </fieldset>\n\n      <fieldset data-step=\"1\" hidden>\n        <legend>Wie viele Tiere sollen versorgt werden?</legend>\n        <p class=\"step-help\">\n          Bei mehreren Tieren können Zugangskontrolle und\n          Futterneid entscheidend sein.\n        </p>\n\n        <div class=\"choice-grid choice-grid--two\">\n          <label class=\"choice-card\">\n            <input\n              type=\"radio\"\n              name=\"petCount\"\n              value=\"one\"\n              required\n            />\n            <span>\n              <strong>Ein Tier</strong>\n              <small>Kein getrennter Zugang nötig</small>\n            </span>\n          </label>\n\n          <label class=\"choice-card\">\n            <input\n              type=\"radio\"\n              name=\"petCount\"\n              value=\"multiple\"\n              required\n            />\n            <span>\n              <strong>Mehrere Tiere</strong>\n              <small>\n                Mikrochip oder getrennte Fütterung prüfen\n              </small>\n            </span>\n          </label>\n        </div>\n      </fieldset>\n\n      <fieldset data-step=\"2\" hidden>\n        <legend>Welches Futter soll ausgegeben werden?</legend>\n        <p class=\"step-help\">\n          Die Futterart ist ein hartes Auswahlkriterium.\n        </p>\n\n        <div class=\"choice-grid choice-grid--three\">\n          <label class=\"choice-card\">\n            <input\n              type=\"radio\"\n              name=\"food\"\n              value=\"dry\"\n              required\n            />\n            <span>\n              <strong>Trockenfutter</strong>\n              <small>Vorrats- und Dosierautomaten</small>\n            </span>\n          </label>\n\n          <label class=\"choice-card\">\n            <input\n              type=\"radio\"\n              name=\"food\"\n              value=\"wet\"\n              required\n            />\n            <span>\n              <strong>Nassfutter</strong>\n              <small>Fächer, Kühlung oder Zeitdeckel</small>\n            </span>\n          </label>\n\n          <label class=\"choice-card\">\n            <input\n              type=\"radio\"\n              name=\"food\"\n              value=\"mixed\"\n              required\n            />\n            <span>\n              <strong>Beides</strong>\n              <small>Flexible Lösung gesucht</small>\n            </span>\n          </label>\n        </div>\n      </fieldset>\n\n      <fieldset data-step=\"3\" hidden>\n        <legend>Welche Funktionen sind dir wichtig?</legend>\n        <p class=\"step-help\">\n          Mehrfachauswahl möglich. Wähle nur, was deinen\n          Alltag wirklich verbessert.\n        </p>\n\n        <div class=\"choice-grid choice-grid--three\">\n          {\n            [\n              [\"camera\", \"Kamera\", \"Tier und Ausgabe sehen\"],\n              [\"app\", \"App\", \"Zeiten mobil verwalten\"],\n              [\"offline\", \"Offline\", \"Plan läuft ohne Internet\"],\n              [\"backup\", \"Notstrom\", \"Bei Stromausfall abgesichert\"],\n              [\"microchip\", \"Mikrochip\", \"Zugang pro Tier steuern\"],\n              [\"simple\", \"Einfach\", \"Möglichst wenig Technik\"]\n            ].map(([value, title, text]) => (\n              <label class=\"choice-card\">\n                <input\n                  type=\"checkbox\"\n                  name=\"priorities\"\n                  value={value}\n                />\n                <span>\n                  <strong>{title}</strong>\n                  <small>{text}</small>\n                </span>\n              </label>\n            ))\n          }\n        </div>\n      </fieldset>\n\n      <fieldset data-step=\"4\" hidden>\n        <legend>Welche Preisklasse passt?</legend>\n        <p class=\"step-help\">\n          Wir verwenden grobe Klassen statt statischer\n          Preisversprechen.\n        </p>\n\n        <div class=\"choice-grid choice-grid--two\">\n          {\n            [\n              [\"budget\", \"Preisbewusst\", \"Grundfunktionen zuerst\"],\n              [\"midrange\", \"Mittelklasse\", \"Gute Balance\"],\n              [\"premium\", \"Premium\", \"Mehr Komfort\"],\n              [\"open\", \"Offen\", \"Eignung vor Preis\"]\n            ].map(([value, title, text]) => (\n              <label class=\"choice-card\">\n                <input\n                  type=\"radio\"\n                  name=\"budget\"\n                  value={value}\n                  required\n                />\n                <span>\n                  <strong>{title}</strong>\n                  <small>{text}</small>\n                </span>\n              </label>\n            ))\n          }\n        </div>\n      </fieldset>\n\n      <fieldset data-step=\"5\" hidden>\n        <legend>Wie soll der Advisor entscheiden?</legend>\n        <p class=\"step-help\">\n          Du kannst entweder die höchste Gesamtpassung oder\n          möglichst wenige Kompromisse priorisieren.\n        </p>\n\n        <div class=\"choice-grid choice-grid--two\">\n          <label class=\"choice-card\">\n            <input\n              type=\"radio\"\n              name=\"decisionStyle\"\n              value=\"best-match\"\n              required\n            />\n            <span>\n              <strong>Beste Gesamtpassung</strong>\n              <small>\n                Alle Antworten ausgewogen gewichten\n              </small>\n            </span>\n          </label>\n\n          <label class=\"choice-card\">\n            <input\n              type=\"radio\"\n              name=\"decisionStyle\"\n              value=\"safe-choice\"\n              required\n            />\n            <span>\n              <strong>Möglichst sichere Wahl</strong>\n              <small>\n                Weniger Einschränkungen priorisieren\n              </small>\n            </span>\n          </label>\n        </div>\n      </fieldset>\n\n      <p\n        class=\"form-error\"\n        data-error\n        hidden\n        role=\"alert\"\n      >\n        Bitte wähle eine Antwort aus.\n      </p>\n\n      <div class=\"advisor-actions\">\n        <button\n          type=\"button\"\n          class=\"button-secondary\"\n          data-back\n          hidden\n        >\n          Zurück\n        </button>\n\n        <button\n          type=\"button\"\n          class=\"button-primary\"\n          data-next\n        >\n          Weiter\n        </button>\n      </div>\n    </form>\n\n    <section\n      class=\"advisor-results\"\n      data-results\n      hidden\n      aria-live=\"polite\"\n    >\n      <div class=\"results-heading\">\n        <p class=\"eyebrow\">Deine Auswahl</p>\n        <h2>Diese Modelle passen am besten</h2>\n        <p data-result-summary></p>\n      </div>\n\n      <p class=\"advisor-disclosure\">\n        Die Auswahl basiert auf dokumentierten\n        Produktmerkmalen und redaktioneller Einordnung.\n        Preise und Verfügbarkeit können sich ändern.\n      </p>\n\n      <div class=\"result-grid\" data-result-list></div>\n\n      <section\n        class=\"compare-section\"\n        data-compare\n        hidden\n        aria-labelledby=\"compare-heading\"\n      >\n        <div class=\"section-heading\">\n          <p>Direktvergleich</p>\n          <h2 id=\"compare-heading\">\n            Nur die Unterschiede\n          </h2>\n        </div>\n\n        <div\n          class=\"compare-scroll\"\n          data-compare-table\n        ></div>\n      </section>\n\n      <section\n        class=\"guide-section\"\n        aria-labelledby=\"guide-heading\"\n      >\n        <div class=\"section-heading\">\n          <p>Passendes Wissen</p>\n          <h2 id=\"guide-heading\">\n            Diese Ratgeber helfen bei der Entscheidung\n          </h2>\n        </div>\n        <div class=\"guide-grid\" data-guide-list></div>\n      </section>\n\n      <div class=\"result-actions\">\n        <button\n          type=\"button\"\n          class=\"button-secondary\"\n          data-restart\n        >\n          Antworten ändern\n        </button>\n\n        <button\n          type=\"button\"\n          class=\"button-secondary\"\n          data-share\n        >\n          Ergebnislink kopieren\n        </button>\n      </div>\n\n      <p class=\"share-status\" data-share-status aria-live=\"polite\"></p>\n    </section>\n  </div>\n</section>\n\n<script>\n  import {\n    parseAdvisorAnswers,\n    recommendAdvisorProducts,\n    serializeAdvisorAnswers\n  } from \"../../domain/advisor\";\n\n  const fitLabels = {\n    excellent: \"Sehr gute Passung\",\n    good: \"Gute Passung\",\n    limited: \"Mit Einschränkungen\"\n  };\n\n  const priorityLabels = {\n    camera: \"Kamera\",\n    app: \"App\",\n    offline: \"Offline\",\n    backup: \"Notstrom\",\n    microchip: \"Mikrochip\",\n    simple: \"Einfache Bedienung\"\n  };\n\n  const root = document.querySelector(\"[data-advisor]\");\n\n  if (root instanceof HTMLElement) {\n    const products = JSON.parse(\n      root.dataset.products ?? \"[]\"\n    );\n    const guides = JSON.parse(\n      root.dataset.guides ?? \"[]\"\n    );\n\n    const form = root.querySelector(\"[data-form]\");\n    const steps = [\n      ...root.querySelectorAll(\"[data-step]\")\n    ];\n    const next = root.querySelector(\"[data-next]\");\n    const back = root.querySelector(\"[data-back]\");\n    const restart = root.querySelector(\"[data-restart]\");\n    const share = root.querySelector(\"[data-share]\");\n    const error = root.querySelector(\"[data-error]\");\n    const status = root.querySelector(\"[data-status]\");\n    const results = root.querySelector(\"[data-results]\");\n    const list = root.querySelector(\"[data-result-list]\");\n    const summary = root.querySelector(\n      \"[data-result-summary]\"\n    );\n    const progress = root.querySelector(\"[data-progress]\");\n    const progressBar = root.querySelector(\n      \"[data-progress-bar]\"\n    );\n    const progressLabel = root.querySelector(\n      \"[data-progress-label]\"\n    );\n    const progressTitle = root.querySelector(\n      \"[data-progress-title]\"\n    );\n    const liveNote = root.querySelector(\"[data-live-note]\");\n    const compare = root.querySelector(\"[data-compare]\");\n    const compareTable = root.querySelector(\n      \"[data-compare-table]\"\n    );\n    const guideList = root.querySelector(\"[data-guide-list]\");\n    const shareStatus = root.querySelector(\n      \"[data-share-status]\"\n    );\n\n    const titles = [\n      \"Tierart\",\n      \"Anzahl\",\n      \"Futterart\",\n      \"Funktionen\",\n      \"Preisklasse\",\n      \"Entscheidungsstil\"\n    ];\n\n    let current = 0;\n    let latestAnswers = null;\n\n    const formAnswers = () => {\n      if (!(form instanceof HTMLFormElement)) {\n        return null;\n      }\n\n      const data = new FormData(form);\n      const pet = data.get(\"pet\");\n      const petCount = data.get(\"petCount\");\n      const food = data.get(\"food\");\n      const budget = data.get(\"budget\");\n      const decisionStyle = data.get(\"decisionStyle\");\n\n      if (\n        !pet ||\n        !petCount ||\n        !food ||\n        !budget ||\n        !decisionStyle\n      ) {\n        return null;\n      }\n\n      return {\n        pet,\n        petCount,\n        food,\n        budget,\n        decisionStyle,\n        priorities: data.getAll(\"priorities\")\n      };\n    };\n\n    const partialCount = () => {\n      if (!(form instanceof HTMLFormElement)) {\n        return products.length;\n      }\n\n      const data = new FormData(form);\n      const selectedFood = data.get(\"food\");\n      const selectedPriorities = data.getAll(\"priorities\");\n\n      return products.filter((product) => {\n        if (\n          selectedFood === \"dry\" &&\n          !product.foodType.includes(\"dry\")\n        ) {\n          return false;\n        }\n\n        if (\n          selectedFood === \"wet\" &&\n          !product.foodType.includes(\"wet\")\n        ) {\n          return false;\n        }\n\n        if (\n          selectedPriorities.includes(\"microchip\") &&\n          product.access !== \"microchip\"\n        ) {\n          return false;\n        }\n\n        return true;\n      }).length;\n    };\n\n    const update = () => {\n      steps.forEach((step, index) => {\n        if (step instanceof HTMLElement) {\n          step.hidden = index !== current;\n        }\n      });\n\n      if (back instanceof HTMLButtonElement) {\n        back.hidden = current === 0;\n      }\n\n      if (next instanceof HTMLButtonElement) {\n        next.textContent =\n          current === steps.length - 1\n            ? \"Empfehlung anzeigen\"\n            : \"Weiter\";\n      }\n\n      const stepNumber = current + 1;\n\n      if (progressLabel) {\n        progressLabel.textContent =\n          `Frage ${stepNumber} von ${steps.length}`;\n      }\n\n      if (progressTitle) {\n        progressTitle.textContent = titles[current];\n      }\n\n      if (progress instanceof HTMLElement) {\n        progress.setAttribute(\n          \"aria-valuenow\",\n          String(stepNumber)\n        );\n      }\n\n      if (progressBar instanceof HTMLElement) {\n        progressBar.style.width =\n          `${(stepNumber / steps.length) * 100}%`;\n      }\n\n      if (liveNote) {\n        const remaining = partialCount();\n        liveNote.textContent =\n          current === 0\n            ? \"Wir starten mit den grundlegenden Anforderungen.\"\n            : `${remaining} von ${products.length} Modellen bleiben nach den bisherigen Angaben grundsätzlich relevant.`;\n      }\n\n      if (error instanceof HTMLElement) {\n        error.hidden = true;\n      }\n    };\n\n    const stepIsValid = () => {\n      const step = steps[current];\n      const required = [\n        ...step.querySelectorAll(\"[required]\")\n      ];\n\n      if (required.length === 0) {\n        return true;\n      }\n\n      const names = [\n        ...new Set(\n          required.map((input) =>\n            input instanceof HTMLInputElement\n              ? input.name\n              : \"\"\n          )\n        )\n      ];\n\n      return names.every((name) =>\n        step.querySelector(\n          `input[name=\"${name}\"]:checked`\n        )\n      );\n    };\n\n    const restoreAnswers = (answers) => {\n      if (!(form instanceof HTMLFormElement)) {\n        return;\n      }\n\n      Object.entries(answers).forEach(([key, value]) => {\n        if (key === \"priorities\" && Array.isArray(value)) {\n          value.forEach((priority) => {\n            const input = form.querySelector(\n              `input[name=\"priorities\"][value=\"${priority}\"]`\n            );\n            if (input instanceof HTMLInputElement) {\n              input.checked = true;\n            }\n          });\n          return;\n        }\n\n        const input = form.querySelector(\n          `input[name=\"${key}\"][value=\"${value}\"]`\n        );\n\n        if (input instanceof HTMLInputElement) {\n          input.checked = true;\n        }\n      });\n    };\n\n    const compareRows = (matches) => {\n      const rows = [\n        [\n          \"Futterart\",\n          (match) =>\n            match.product.foodType\n              .map((type) =>\n                type === \"dry\"\n                  ? \"Trockenfutter\"\n                  : \"Nassfutter\"\n              )\n              .join(\" & \") || \"Nicht dokumentiert\"\n        ],\n        [\n          \"App\",\n          (match) =>\n            match.product.app === true\n              ? \"Ja\"\n              : \"Nicht ausgewiesen\"\n        ],\n        [\n          \"Kamera\",\n          (match) =>\n            match.product.camera === true ? \"Ja\" : \"Nein\"\n        ],\n        [\n          \"Zugang\",\n          (match) =>\n            match.product.access === \"microchip\"\n              ? \"Mikrochip\"\n              : \"Offen\"\n        ],\n        [\n          \"Notstrom\",\n          (match) =>\n            match.product.backupPower === true\n              ? \"Ja\"\n              : \"Nicht ausgewiesen\"\n        ],\n        [\n          \"Preisklasse\",\n          (match) =>\n            ({\n              budget: \"Preisbewusst\",\n              midrange: \"Mittelklasse\",\n              premium: \"Premium\"\n            })[match.product.priceCategory] ??\n            \"Nicht eingeordnet\"\n        ]\n      ];\n\n      return rows.filter(([, value]) => {\n        const values = matches.map(value);\n        return new Set(values).size > 1;\n      });\n    };\n\n    const renderCompare = (matches) => {\n      if (\n        !(compare instanceof HTMLElement) ||\n        !(compareTable instanceof HTMLElement) ||\n        matches.length < 2\n      ) {\n        return;\n      }\n\n      const rows = compareRows(matches);\n\n      if (rows.length === 0) {\n        compare.hidden = true;\n        return;\n      }\n\n      compareTable.innerHTML = `\n        <table>\n          <thead>\n            <tr>\n              <th scope=\"col\">Kriterium</th>\n              ${matches\n                .map(\n                  (match) =>\n                    `<th scope=\"col\">${match.product.title}</th>`\n                )\n                .join(\"\")}\n            </tr>\n          </thead>\n          <tbody>\n            ${rows\n              .map(\n                ([label, value]) => `\n                  <tr>\n                    <th scope=\"row\">${label}</th>\n                    ${matches\n                      .map(\n                        (match) =>\n                          `<td>${value(match)}</td>`\n                      )\n                      .join(\"\")}\n                  </tr>\n                `\n              )\n              .join(\"\")}\n          </tbody>\n        </table>\n      `;\n\n      compare.hidden = false;\n    };\n\n    const renderGuides = (answers) => {\n      if (!(guideList instanceof HTMLElement)) {\n        return;\n      }\n\n      const selected = guides\n        .filter((guide) => {\n          if (guide.href.includes(\"zwei-katzen\")) {\n            return answers.petCount === \"multiple\";\n          }\n\n          if (guide.href.includes(\"nassfutter\")) {\n            return (\n              answers.food === \"wet\" ||\n              answers.food === \"mixed\"\n            );\n          }\n\n          if (guide.href.includes(\"ohne-wlan\")) {\n            return answers.priorities.includes(\"offline\");\n          }\n\n          if (guide.href.includes(\"mit-kamera\")) {\n            return answers.priorities.includes(\"camera\");\n          }\n\n          return true;\n        })\n        .slice(0, 4);\n\n      guideList.innerHTML = selected\n        .map(\n          (guide) => `\n            <a class=\"guide-card\" href=\"${guide.href}\">\n              <strong>${guide.title}</strong>\n              <span>${guide.description}</span>\n            </a>\n          `\n        )\n        .join(\"\");\n    };\n\n    const renderResults = () => {\n      if (\n        !(form instanceof HTMLFormElement) ||\n        !(results instanceof HTMLElement) ||\n        !(list instanceof HTMLElement)\n      ) {\n        return;\n      }\n\n      const answers = formAnswers();\n      if (!answers) {\n        return;\n      }\n\n      latestAnswers = answers;\n\n      const params = serializeAdvisorAnswers(answers);\n      history.replaceState(\n        null,\n        \"\",\n        `${window.location.pathname}?${params.toString()}`\n      );\n\n      localStorage.setItem(\n        \"pfotentechnik-advisor\",\n        JSON.stringify(answers)\n      );\n\n      const matches = recommendAdvisorProducts(\n        products,\n        answers\n      )\n        .filter((match) => match.fit !== \"none\")\n        .slice(0, 3);\n\n      list.innerHTML = \"\";\n\n      if (summary) {\n        summary.textContent =\n          matches.length > 0\n            ? `${matches.length} Modelle erfüllen deine wichtigsten Anforderungen am besten.`\n            : \"Aktuell erfüllt kein Modell alle entscheidenden Anforderungen ohne deutliche Einschränkung.\";\n      }\n\n      matches.forEach((match, index) => {\n        const card = document.createElement(\"article\");\n        card.className = \"result-card\";\n        card.innerHTML = `\n          <div class=\"result-meta\">\n            <span>\n              ${\n                index === 0\n                  ? \"Beste Gesamtpassung\"\n                  : `Alternative ${index}`\n              }\n            </span>\n            <strong>${fitLabels[match.fit]}</strong>\n          </div>\n\n          <h3>${match.product.title}</h3>\n          <p>\n            ${\n              match.product.recommendation ||\n              match.product.description\n            }\n          </p>\n\n          <div class=\"fit-badge fit-badge--${match.fit}\">\n            ${fitLabels[match.fit]}\n          </div>\n\n          <h4>Warum es passt</h4>\n          <ul class=\"reason-list\">\n            ${match.reasons\n              .map((reason) => `<li>${reason}</li>`)\n              .join(\"\")}\n          </ul>\n\n          ${\n            match.cautions.length > 0\n              ? `\n                <details>\n                  <summary>\n                    Einschränkungen ansehen\n                  </summary>\n                  <ul>\n                    ${match.cautions\n                      .map(\n                        (caution) =>\n                          `<li>${caution}</li>`\n                      )\n                      .join(\"\")}\n                  </ul>\n                </details>\n              `\n              : \"\"\n          }\n\n          <a\n            class=\"button-primary result-link\"\n            href=\"${match.product.route}\"\n          >\n            Testbericht ansehen\n          </a>\n        `;\n\n        list.appendChild(card);\n      });\n\n      renderCompare(matches);\n      renderGuides(answers);\n\n      form.hidden = true;\n      if (status instanceof HTMLElement) {\n        status.hidden = true;\n      }\n      results.hidden = false;\n      results.scrollIntoView({\n        behavior: \"smooth\",\n        block: \"start\"\n      });\n    };\n\n    next?.addEventListener(\"click\", () => {\n      if (!stepIsValid()) {\n        if (error instanceof HTMLElement) {\n          error.hidden = false;\n        }\n\n        const firstInput =\n          steps[current].querySelector(\"input\");\n\n        if (firstInput instanceof HTMLInputElement) {\n          firstInput.focus();\n        }\n\n        return;\n      }\n\n      if (current === steps.length - 1) {\n        renderResults();\n        return;\n      }\n\n      current += 1;\n      update();\n    });\n\n    back?.addEventListener(\"click\", () => {\n      current = Math.max(0, current - 1);\n      update();\n    });\n\n    restart?.addEventListener(\"click\", () => {\n      if (results instanceof HTMLElement) {\n        results.hidden = true;\n      }\n\n      if (form instanceof HTMLFormElement) {\n        form.hidden = false;\n      }\n\n      if (status instanceof HTMLElement) {\n        status.hidden = false;\n      }\n\n      current = 0;\n      update();\n\n      form?.scrollIntoView({\n        behavior: \"smooth\",\n        block: \"start\"\n      });\n    });\n\n    share?.addEventListener(\"click\", async () => {\n      if (!latestAnswers) {\n        return;\n      }\n\n      try {\n        await navigator.clipboard.writeText(\n          window.location.href\n        );\n        if (shareStatus) {\n          shareStatus.textContent =\n            \"Der Ergebnislink wurde kopiert.\";\n        }\n      } catch {\n        if (shareStatus) {\n          shareStatus.textContent =\n            \"Der Link konnte nicht automatisch kopiert werden.\";\n        }\n      }\n    });\n\n    const fromUrl = parseAdvisorAnswers(\n      new URLSearchParams(window.location.search)\n    );\n\n    if (fromUrl) {\n      restoreAnswers(fromUrl);\n      renderResults();\n    } else {\n      const saved = localStorage.getItem(\n        \"pfotentechnik-advisor\"\n      );\n\n      if (saved) {\n        try {\n          restoreAnswers(JSON.parse(saved));\n        } catch {\n          localStorage.removeItem(\n            \"pfotentechnik-advisor\"\n          );\n        }\n      }\n\n      update();\n    }\n  }\n</script>\n\n<style>\n  .advisor {\n    width: min(1160px, calc(100% - 32px));\n    margin: 48px auto 96px;\n  }\n\n  .advisor-hero {\n    max-width: 860px;\n    margin-bottom: 34px;\n  }\n\n  .eyebrow,\n  .section-heading p {\n    margin: 0 0 8px;\n    color: #2e7d32;\n    font-size: 0.8rem;\n    font-weight: 800;\n    letter-spacing: 0.09em;\n    text-transform: uppercase;\n  }\n\n  .advisor-hero h1 {\n    margin: 0;\n    color: #0f172a;\n    font-size: clamp(2.35rem, 6vw, 4.8rem);\n    line-height: 1.02;\n    letter-spacing: -0.045em;\n  }\n\n  .lead {\n    max-width: 760px;\n    color: #475569;\n    font-size: 1.12rem;\n    line-height: 1.72;\n  }\n\n  .trust-row {\n    display: flex;\n    flex-wrap: wrap;\n    gap: 8px;\n  }\n\n  .trust-row span {\n    padding: 8px 12px;\n    border-radius: 999px;\n    background: #f0fdf4;\n    color: #166534;\n    font-size: 0.82rem;\n    font-weight: 750;\n  }\n\n  .advisor-panel {\n    padding: clamp(20px, 4vw, 50px);\n    border: 1px solid #e2e8f0;\n    border-radius: 32px;\n    background: #ffffff;\n    box-shadow:\n      0 30px 90px rgba(15, 23, 42, 0.09);\n  }\n\n  .advisor-status {\n    margin-bottom: 38px;\n  }\n\n  .status-copy {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    gap: 16px;\n    color: #64748b;\n  }\n\n  .status-copy strong {\n    color: #0f172a;\n  }\n\n  .progress-track {\n    overflow: hidden;\n    height: 8px;\n    margin-top: 12px;\n    border-radius: 999px;\n    background: #e2e8f0;\n  }\n\n  .progress-track span {\n    display: block;\n    height: 100%;\n    border-radius: inherit;\n    background: #2e7d32;\n    transition: width 180ms ease;\n  }\n\n  .live-note {\n    margin: 12px 0 0;\n    color: #64748b;\n    font-size: 0.88rem;\n  }\n\n  fieldset {\n    min-width: 0;\n    margin: 0;\n    padding: 0;\n    border: 0;\n  }\n\n  legend {\n    max-width: 780px;\n    color: #0f172a;\n    font-size: clamp(1.65rem, 4vw, 2.65rem);\n    font-weight: 850;\n    line-height: 1.14;\n    letter-spacing: -0.025em;\n  }\n\n  .step-help {\n    max-width: 680px;\n    margin: 10px 0 0;\n    color: #64748b;\n    line-height: 1.6;\n  }\n\n  .choice-grid {\n    display: grid;\n    gap: 14px;\n    margin-top: 26px;\n  }\n\n  .choice-grid--two {\n    grid-template-columns:\n      repeat(2, minmax(0, 1fr));\n  }\n\n  .choice-grid--three {\n    grid-template-columns:\n      repeat(3, minmax(0, 1fr));\n  }\n\n  .choice-card {\n    position: relative;\n    cursor: pointer;\n  }\n\n  .choice-card input {\n    position: absolute;\n    opacity: 0;\n    pointer-events: none;\n  }\n\n  .choice-card > span {\n    display: flex;\n    min-height: 124px;\n    flex-direction: column;\n    justify-content: center;\n    padding: 22px;\n    border: 2px solid #e2e8f0;\n    border-radius: 21px;\n    background: #ffffff;\n    transition:\n      border-color 150ms ease,\n      background 150ms ease,\n      transform 150ms ease,\n      box-shadow 150ms ease;\n  }\n\n  .choice-card strong {\n    color: #0f172a;\n    font-size: 1.04rem;\n  }\n\n  .choice-card small,\n  .choice-card em {\n    margin-top: 6px;\n    color: #64748b;\n    font-style: normal;\n    line-height: 1.45;\n  }\n\n  .choice-card input:checked + span {\n    border-color: #2e7d32;\n    background: #f0fdf4;\n    box-shadow:\n      0 10px 28px rgba(46, 125, 50, 0.1);\n  }\n\n  .choice-card input:focus-visible + span {\n    outline: 3px solid rgba(79, 70, 229, 0.32);\n    outline-offset: 4px;\n  }\n\n  .choice-card:hover > span {\n    transform: translateY(-1px);\n  }\n\n  .advisor-actions,\n  .result-actions {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    gap: 12px;\n    margin-top: 34px;\n  }\n\n  .button-primary,\n  .button-secondary {\n    display: inline-flex;\n    min-height: 50px;\n    align-items: center;\n    justify-content: center;\n    padding: 12px 22px;\n    border-radius: 13px;\n    font: inherit;\n    font-weight: 800;\n    text-decoration: none;\n    cursor: pointer;\n  }\n\n  .button-primary {\n    border: 1px solid #2e7d32;\n    background: #2e7d32;\n    color: #ffffff;\n  }\n\n  .button-primary:hover {\n    background: #256b2a;\n  }\n\n  .button-secondary {\n    border: 1px solid #cbd5e1;\n    background: #ffffff;\n    color: #0f172a;\n  }\n\n  .form-error {\n    margin-top: 20px;\n    padding: 12px 14px;\n    border-radius: 12px;\n    background: #fef2f2;\n    color: #991b1b;\n  }\n\n  .results-heading {\n    max-width: 760px;\n  }\n\n  .results-heading h2,\n  .section-heading h2 {\n    margin: 0;\n    color: #0f172a;\n    font-size: clamp(1.75rem, 4vw, 2.8rem);\n    line-height: 1.12;\n  }\n\n  .advisor-disclosure {\n    margin: 22px 0 0;\n    padding: 15px 16px;\n    border-radius: 14px;\n    background: #f8fafc;\n    color: #475569;\n    line-height: 1.55;\n  }\n\n  .result-grid {\n    display: grid;\n    grid-template-columns:\n      repeat(3, minmax(0, 1fr));\n    gap: 16px;\n    margin-top: 30px;\n  }\n\n  .result-card {\n    display: flex;\n    min-width: 0;\n    flex-direction: column;\n    padding: 23px;\n    border: 1px solid #e2e8f0;\n    border-radius: 21px;\n    background: #ffffff;\n  }\n\n  .result-card:first-child {\n    border-color: #86efac;\n    box-shadow:\n      0 18px 44px rgba(46, 125, 50, 0.11);\n  }\n\n  .result-meta {\n    display: flex;\n    justify-content: space-between;\n    gap: 12px;\n    color: #166534;\n    font-size: 0.78rem;\n    font-weight: 800;\n    text-transform: uppercase;\n  }\n\n  .result-card h3 {\n    margin: 16px 0 8px;\n    color: #0f172a;\n    font-size: 1.3rem;\n  }\n\n  .result-card > p {\n    color: #475569;\n    line-height: 1.58;\n  }\n\n  .fit-badge {\n    align-self: flex-start;\n    margin-top: 8px;\n    padding: 7px 10px;\n    border-radius: 999px;\n    font-size: 0.8rem;\n    font-weight: 800;\n  }\n\n  .fit-badge--excellent,\n  .fit-badge--good {\n    background: #f0fdf4;\n    color: #166534;\n  }\n\n  .fit-badge--limited {\n    background: #fffbeb;\n    color: #92400e;\n  }\n\n  .result-card h4 {\n    margin: 22px 0 8px;\n    color: #0f172a;\n    font-size: 0.92rem;\n  }\n\n  .reason-list,\n  .result-card details ul {\n    margin: 0;\n    padding-left: 20px;\n    color: #334155;\n    line-height: 1.58;\n  }\n\n  .result-card details {\n    margin: 16px 0;\n    color: #92400e;\n  }\n\n  .result-link {\n    margin-top: auto;\n  }\n\n  .compare-section,\n  .guide-section {\n    margin-top: 48px;\n    padding-top: 38px;\n    border-top: 1px solid #e2e8f0;\n  }\n\n  .compare-scroll {\n    overflow-x: auto;\n    margin-top: 22px;\n    border: 1px solid #e2e8f0;\n    border-radius: 18px;\n  }\n\n  .compare-scroll table {\n    width: 100%;\n    min-width: 720px;\n    border-collapse: collapse;\n  }\n\n  .compare-scroll th,\n  .compare-scroll td {\n    padding: 16px;\n    border-bottom: 1px solid #e2e8f0;\n    text-align: left;\n    vertical-align: top;\n  }\n\n  .compare-scroll thead th {\n    background: #f8fafc;\n  }\n\n  .guide-grid {\n    display: grid;\n    grid-template-columns:\n      repeat(2, minmax(0, 1fr));\n    gap: 14px;\n    margin-top: 22px;\n  }\n\n  .guide-card {\n    display: flex;\n    flex-direction: column;\n    gap: 7px;\n    padding: 19px;\n    border: 1px solid #e2e8f0;\n    border-radius: 17px;\n    color: #0f172a;\n    text-decoration: none;\n  }\n\n  .guide-card span {\n    color: #64748b;\n    line-height: 1.5;\n  }\n\n  .guide-card:hover {\n    border-color: #86efac;\n    background: #f0fdf4;\n  }\n\n  .share-status {\n    min-height: 1.5em;\n    color: #166534;\n  }\n\n  @media (max-width: 840px) {\n    .choice-grid--three,\n    .result-grid {\n      grid-template-columns: 1fr;\n    }\n  }\n\n  @media (max-width: 640px) {\n    .advisor {\n      width: min(100% - 20px, 1160px);\n      margin-top: 22px;\n    }\n\n    .advisor-panel {\n      padding: 18px;\n      border-radius: 21px;\n    }\n\n    .choice-grid--two,\n    .guide-grid {\n      grid-template-columns: 1fr;\n    }\n\n    .choice-card > span {\n      min-height: 94px;\n    }\n\n    .advisor-actions {\n      position: sticky;\n      z-index: 3;\n      bottom: 0;\n      padding-top: 22px;\n      background:\n        linear-gradient(\n          to bottom,\n          transparent,\n          #ffffff 28%\n        );\n    }\n\n    .advisor-actions,\n    .result-actions {\n      align-items: stretch;\n      flex-direction: column-reverse;\n    }\n\n    .advisor-actions > *,\n    .result-actions > * {\n      width: 100%;\n    }\n\n    .result-meta {\n      align-items: flex-start;\n      flex-direction: column;\n    }\n  }\n\n  @media (prefers-reduced-motion: reduce) {\n    *,\n    *::before,\n    *::after {\n      scroll-behavior: auto !important;\n      transition: none !important;\n    }\n  }\n</style>\n", "apps/pfotentechnik/src/pages/futterautomat-berater.astro": "---\nimport { getCollection } from \"astro:content\";\nimport ProjectLayout from \"../layouts/ProjectLayout.astro\";\nimport PetAdvisor from \"../components/advisor/PetAdvisor.astro\";\nimport { mapProductToAdvisor } from \"../domain/advisor\";\n\nconst products = (await getCollection(\"products\"))\n  .filter(\n    (entry) =>\n      entry.data.category.key === \"futterautomat\"\n  )\n  .map(mapProductToAdvisor);\n---\n\n<ProjectLayout\n  title=\"Futterautomaten-Berater: Welches Modell passt? | PfotenTechnik\"\n  description=\"Beantworte sechs kurze Fragen und finde passende Futterautomaten für Tier, Futterart, Alltag, Funktionen und Budget.\"\n  canonical=\"/futterautomat-berater/\"\n  schemaType=\"website\"\n>\n  <PetAdvisor products={products} />\n</ProjectLayout>\n", "apps/pfotentechnik/src/pages/api/advisor-products.json.ts": "import type { APIRoute } from \"astro\";\nimport { getCollection } from \"astro:content\";\nimport { mapProductToAdvisor } from \"../../domain/advisor\";\n\nexport const GET: APIRoute = async () => {\n  const products = (await getCollection(\"products\"))\n    .filter(\n      (entry) =>\n        entry.data.category.key === \"futterautomat\"\n    )\n    .map(mapProductToAdvisor);\n\n  return new Response(\n    JSON.stringify({\n      generatedAt: new Date().toISOString(),\n      products\n    }),\n    {\n      headers: {\n        \"Content-Type\":\n          \"application/json; charset=utf-8\",\n        \"Cache-Control\":\n          \"public, max-age=3600\"\n      }\n    }\n  );\n};\n", "apps/pfotentechnik/src/domain/advisor/recommendProducts.test.mjs": "import assert from \"node:assert/strict\";\nimport { recommendAdvisorProducts } from \"./recommendProducts.ts\";\n\nconst products = [\n  {\n    id: \"microchip\",\n    slug: \"microchip\",\n    title: \"Microchip Feeder\",\n    description: \"\",\n    recommendation: \"Für mehrere Katzen\",\n    rating: 4.6,\n    bestFor: [\"Mehrkatzenhaushalt\"],\n    attention: [],\n    strengths: [\"Mikrochip\"],\n    weaknesses: [],\n    features: [\"Mikrochip\"],\n    foodType: [\"dry\", \"wet\"],\n    access: \"microchip\",\n    priceCategory: \"premium\",\n    route: \"/produkt/microchip/\"\n  },\n  {\n    id: \"camera\",\n    slug: \"camera\",\n    title: \"Camera Feeder\",\n    description: \"\",\n    recommendation: \"Für Katzen mit Kamera\",\n    rating: 4.5,\n    bestFor: [\"Katze\"],\n    attention: [],\n    strengths: [\"Kamera\", \"App\"],\n    weaknesses: [],\n    features: [\"Kamera\", \"App\"],\n    foodType: [\"dry\"],\n    camera: true,\n    app: true,\n    priceCategory: \"midrange\",\n    route: \"/produkt/camera/\"\n  }\n];\n\nconst multiPet = recommendAdvisorProducts(products, {\n  pet: \"cat\",\n  petCount: \"multiple\",\n  food: \"mixed\",\n  budget: \"open\",\n  priorities: [\"microchip\"],\n  decisionStyle: \"safe-choice\"\n});\n\nassert.equal(multiPet[0].product.id, \"microchip\");\n\nconst camera = recommendAdvisorProducts(products, {\n  pet: \"cat\",\n  petCount: \"one\",\n  food: \"dry\",\n  budget: \"midrange\",\n  priorities: [\"camera\", \"app\"],\n  decisionStyle: \"best-match\"\n});\n\nassert.equal(camera[0].product.id, \"camera\");\n\nconsole.log(\"Advisor 2.0 recommendation tests passed.\");\n", "docs/ADVISOR_2_ROLLOUT_CHECKLIST.md": "# Advisor 2.0 Rollout\n\n## Technisch\n\n- [ ] Installer ausführen\n- [ ] `npm run build:pfotentechnik`\n- [ ] Route öffnet ohne Fehler\n- [ ] keine Hydration-Fehler\n- [ ] keine leeren Produktergebnisse durch fehlende Filterdaten\n\n## UX\n\n- [ ] Android 360 px\n- [ ] iPhone 390 px\n- [ ] Tablet\n- [ ] Desktop\n- [ ] Tastaturbedienung\n- [ ] sichtbarer Fokus\n- [ ] reduzierte Bewegung\n- [ ] Ergebnislink funktioniert\n- [ ] lokale Wiederherstellung funktioniert\n\n## Inhalt\n\n- [ ] Nassfutter schließt Trockenfutter-only aus\n- [ ] Mikrochip priorisiert Zugangskontrolle\n- [ ] mehrere Tiere erzeugt passenden Hinweis\n- [ ] Kamera zeigt passenden Ratgeber\n- [ ] Offline zeigt passenden Ratgeber\n- [ ] maximal drei Ergebnisse\n\n## Integration\n\n- [ ] Cornerstone verlinkt\n- [ ] Startseite verlinkt\n- [ ] Vergleichsübersicht verlinkt\n- [ ] Analytics erst nach Freigabe\n"};

for (const [relativePath, content] of Object.entries(files)) {
  const target = path.join(
    process.cwd(),
    relativePath
  );

  if (fs.existsSync(target)) {
    console.error(
      `Abbruch: ${relativePath} existiert bereits.`
    );
    process.exit(1);
  }

  fs.mkdirSync(
    path.dirname(target),
    { recursive: true }
  );
  fs.writeFileSync(target, content, "utf8");
  console.log(`erstellt: ${relativePath}`);
}

console.log(
  "\nPfotenTechnik Advisor 2.0 installiert."
);
console.log(
  "Jetzt ausführen: npm run build:pfotentechnik"
);
